import 'package:flutter/material.dart';
import '../config/app_config.dart';

class VaultPage extends StatefulWidget {
  @override
  _VaultPageState createState() => _VaultPageState();
}

class _VaultPageState extends State<VaultPage> {
  bool _isLocked = true;
  String _pin = '';
  final String _correctPin = '2024';
  String _statusMessage = 'Vault Encrypted';

  void _handlePinPress(String value) {
    if (_pin.length < 4) {
      setState(() {
        _pin += value;
        if (_pin.length == 4) {
          if (_pin == _correctPin) {
            _isLocked = false;
            _statusMessage = 'Access Granted';
          } else {
            _pin = '';
            _statusMessage = 'Incorrect PIN. Try 2024';
          }
        }
      });
    }
  }

  void _lockVault() {
    setState(() {
      _pin = '';
      _isLocked = true;
      _statusMessage = 'Vault Encrypted';
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppConfig.backgroundColor,
      appBar: AppBar(
        backgroundColor: Colors.transparent,
        elevation: 0,
        title: Text('Encrypted Vault', style: TextStyle(color: Colors.black87, fontWeight: FontWeight.bold, fontSize: 20)),
        centerTitle: true,
        actions: [
          if (!_isLocked)
            IconButton(
              icon: Icon(Icons.lock_open, color: AppConfig.primaryColor),
              onPressed: _lockVault,
            )
        ],
      ),
      body: Padding(
        padding: const EdgeInsets.symmetric(horizontal: AppConfig.borderRadius),
        child: _isLocked ? _buildLockScreen() : _buildVaultContent(),
      ),
    );
  }

  Widget _buildLockScreen() {
    return Column(
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        Spacer(),
        Container(
          padding: EdgeInsets.all(24),
          decoration: BoxDecoration(
            color: AppConfig.primaryColor.withOpacity(0.15),
            shape: BoxShape.circle,
          ),
          child: Icon(
            Icons.fingerprint,
            size: 72,
            color: AppConfig.primaryColor,
          ),
        ),
        SizedBox(height: 24),
        Text(
          _statusMessage,
          style: TextStyle(fontWeight: FontWeight.w600, fontSize: 18, color: Colors.black54),
        ),
        SizedBox(height: 12),
        Row(
          mainAxisAlignment: MainAxisAlignment.center,
          children: List.generate(4, (index) {
            return Container(
              margin: EdgeInsets.symmetric(horizontal: 8),
              width: 16,
              height: 16,
              decoration: BoxDecoration(
                color: index < _pin.length ? AppConfig.primaryColor : Colors.grey.withOpacity(0.3),
                shape: BoxShape.circle,
              ),
            );
          }),
        ),
        Spacer(),
        _buildPinPad(),
        SizedBox(height: 40),
      ],
    );
  }

  Widget _buildPinPad() {
    return GridView.builder(
      shrinkWrap: true,
      physics: NeverScrollableScrollPhysics(),
      gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: 3,
        childAspectRatio: 1.5,
        mainAxisSpacing: 10,
        crossAxisSpacing: 10,
      ),
      itemCount: 12,
      itemBuilder: (context, index) {
        String buttonText = '';
        if (index < 9) buttonText = '${index + 1}';
        if (index == 9) buttonText = 'Clear';
        if (index == 10) buttonText = '0';
        if (index == 11) buttonText = 'Biometrics';

        return InkWell(
          onTap: () {
            if (buttonText == 'Clear') {
              setState(() => _pin = '');
            } else if (buttonText == 'Biometrics') {
              setState(() {
                _isLocked = false;
                _statusMessage = 'Unlocked via Face ID';
              });
            } else if (buttonText.isNotEmpty) {
              _handlePinPress(buttonText);
            }
          },
          borderRadius: BorderRadius.circular(AppConfig.borderRadius),
          child: Container(
            decoration: BoxDecoration(
              color: AppConfig.cardColor,
              borderRadius: BorderRadius.circular(AppConfig.borderRadius),
              boxShadow: [
                BoxShadow(color: Colors.black.withOpacity(0.03), blurRadius: 6, offset: Offset(0, 3))
              ],
            ),
            alignment: Alignment.center,
            child: Text(
              buttonText,
              style: TextStyle(
                fontSize: buttonText.length > 2 ? 14 : 20,
                fontWeight: FontWeight.bold,
                color: Colors.black87,
              ),
            ),
          ),
        );
      },
    );
  }

  Widget _buildVaultContent() {
    final List<Map<String, String>> secureCredentials = [
      {'title': 'Main Email Password', 'user': 'user@safespace.privacy', 'secret': '•••••••••••••'},
      {'title': 'Crypto Ledger Phrase', 'user': 'SafeSpace Hardware Key', 'secret': '12 Words Secured'},
      {'title': 'Personal Cloud Backup', 'user': 'cloud_key_441', 'secret': '•••••••••••••'},
    ];

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        SizedBox(height: 20),
        Container(
          width: double.infinity,
          padding: EdgeInsets.all(20),
          decoration: BoxDecoration(
            gradient: LinearGradient(colors: [AppConfig.primaryColor, AppConfig.secondaryColor]),
            borderRadius: BorderRadius.circular(AppConfig.borderRadius),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Icon(Icons.lock, color: Colors.white, size: 36),
              SizedBox(height: 12),
              Text('Hardware Sandbox Active', style: TextStyle(color: Colors.white, fontSize: 18, fontWeight: FontWeight.bold)),
              SizedBox(height: 4),
              Text('All credentials are fully encrypted using military-grade hardware module encryption key.', style: TextStyle(color: Colors.white.withOpacity(0.9), fontSize: 13)),
            ],
          ),
        ),
        SizedBox(height: 24),
        Text('Secure Hardware Passwords', style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold, color: Colors.black87)),
        SizedBox(height: 12),
        Expanded(
          child: ListView.builder(
            itemCount: secureCredentials.length,
            itemBuilder: (context, index) {
              final credential = secureCredentials[index];
              return Container(
                margin: EdgeInsets.only(bottom: 12),
                padding: EdgeInsets.all(16),
                decoration: BoxDecoration(
                  color: AppConfig.cardColor,
                  borderRadius: BorderRadius.circular(AppConfig.borderRadius),
                  boxShadow: [
                    BoxShadow(color: Colors.black.withOpacity(0.02), blurRadius: 10, offset: Offset(0, 4))
                  ],
                ),
                child: Row(
                  children: [
                    Container(
                      padding: EdgeInsets.all(10),
                      decoration: BoxDecoration(
                        color: AppConfig.primaryColor.withOpacity(0.1),
                        shape: BoxShape.circle,
                      ),
                      child: Icon(Icons.key, color: AppConfig.primaryColor),
                    ),
                    SizedBox(width: 16),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(credential['title']!, style: TextStyle(fontWeight: FontWeight.bold, fontSize: 15)),
                          Text(credential['user']!, style: TextStyle(color: Colors.grey, fontSize: 12)),
                          SizedBox(height: 4),
                          Text(credential['secret']!, style: TextStyle(color: AppConfig.secondaryColor, fontWeight: FontWeight.w600, fontSize: 14)),
                        ],
                      ),
                    ),
                    IconButton(
                      icon: Icon(Icons.copy, color: Colors.grey),
                      onPressed: () {
                        ScaffoldMessenger.of(context).showSnackBar(
                          SnackBar(content: Text('Copied securely to memory clipboard!'), backgroundColor: AppConfig.primaryColor),
                        );
                      },
                    ),
                  ],
                ),
              );
            },
          ),
        ),
      ],
    );
