class JournalPage extends StatefulWidget {
  @override
  _JournalPageState createState() => _JournalPageState();
}

class _JournalPageState extends State<JournalPage> {
  final List<Map<String, String>> _journals = [
    {
      'date': 'Oct 24, 2024',
      'mood': '🌸 Calm',
      'thought': 'Felt very secure today using offline-only storage. My peace of mind matters more than anything.'
    },
    {
      'date': 'Oct 23, 2024',
      'mood': '🌻 Happy',
      'thought': 'Enjoyed a mindful tea. No tracking, no analytical networks watching, just plain digital silence.'
    }
  ];

  final TextEditingController _thoughtController = TextEditingController();
  String _selectedMood = '🌸 Calm';

  void _addJournalEntry() {
    if (_thoughtController.text.isNotEmpty) {
      setState(() {
        _journals.insert(0, {
          'date': 'Today',
          'mood': _selectedMood,
          'thought': _thoughtController.text,
        });
        _thoughtController.clear();
      });
      Navigator.pop(context);
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Local-only journal entry saved successfully.'), backgroundColor: AppConfig.primaryColor),
      );
    }
  }

  void _showAddJournalSheet() {
    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      backgroundColor: AppConfig.backgroundColor,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(AppConfig.borderRadius)),
      ),
      builder: (context) {
        return StatefulBuilder(
          builder: (BuildContext context, StateSetter setModalState) {
            return Padding(
              padding: EdgeInsets.only(
