                    Row(
                      mainAxisAlignment: MainAxisAlignment.spaceEvenly,
                      children: ['🌸 Calm', '🌻 Happy', '🛡️ Protected', '🧸 Cozy'].map((mood) {
                        return ChoiceChip(
                          label: Text(mood),
                          selected: _selectedMood == mood,
                          selectedColor: AppConfig.primaryColor.withOpacity(0.2),
                          onSelected: (selected) {
